import { useEffect } from "react";
import { useLocation } from "react-router-dom"
import { TabEventClient } from "../CachedTabs";
import { useRefFunction } from "../../../hooks";

export const useTabOnShow = (func: () => void) => {
    const location = useLocation();
    const onShowFunc = useRefFunction(() => func?.())
    useEffect(() => {
        onShowFunc?.();
        TabEventClient?.addOnShowFunc(TabEventClient?.getKeyByPath(location.pathname) as string, onShowFunc);

        return () => {
            TabEventClient?.removeOnShowFunc(TabEventClient?.getKeyByPath(location.pathname) as string, onShowFunc);
        }
    }, [])
}

export const useTabOnHide = (func: () => void) => {
    const location = useLocation();
    const onHideFunc = useRefFunction(() => func?.())
    useEffect(() => {

        TabEventClient?.addOnHideFunc(TabEventClient?.getKeyByPath(location.pathname) as string, onHideFunc);

        return () => {
            TabEventClient?.removeOnHideFunc(TabEventClient?.getKeyByPath(location.pathname) as string, onHideFunc);
        }
    }, [])
}

